exercises.solution_code:
#include <iostream>

class Color {
    int m_r{0};
    int m_g{0};
    int m_b{0};
public:
    Color() = default;

    friend std::istream& operator>>(std::istream& in, Color& c);
    friend std::ostream& operator<<(std::ostream& out, const Color& c);
};

std::istream& operator>>(std::istream& in, Color& c) {
    in >> c.m_r >> c.m_g >> c.m_b;
    return in;
}

std::ostream& operator<<(std::ostream& out, const Color& c) {
    out << "rgb(" << c.m_r << ", " << c.m_g << ", " << c.m_b << ')';
    return out;
}

int main() {
    Color c;
    std::cin >> c;
    std::cout << c << '\n';
    return 0;
}
